      "type": "array",
      "items": {
        "$ref": "#/$defs/GapItem"
      }
    },
    "evidence": {
      "type": "array",
      "items": {}
    },
    "reasoning_summary": {
      "type": "string",
      "minLength": 1
    }
  },
  "additionalProperties": false,
  "$defs": {
    "BusinessExpectation": {
      "type": "object",
      "properties": {
        "expectation_id": {
          "type": "string",
          "minLength": 1
        },
