      "blocking": false,
      "confidence": 1.0
    },
    {
      "expectation_id": "提取关键实体“重疾险”",
      "status": "not_fulfilled",
      "score": 0,
      "downstream_impact": "无法确定筛选条件，客户画像查询无法聚焦重疾险客户",
      "blocking": true,
      "confidence": 1.0
    },
    {
      "expectation_id": "未错误回退到其他意图",
      "status": "not_fulfilled",
      "score": 0,
      "downstream_impact": "意图被降级为other，可能触发兜底回复或流程中断",
      "blocking": true,
