  },
  "expected": {
    "intent": "customer_portrait",
    "confidence": ">=0.7",
    "target_value": "重疾险"
  },
  "missing": [
    {
      "kind": "intent_label",
      "error_type": "incorrect",
      "expected": "customer_portrait",
      "actual": "other",
      "evidence_ref": "adapter_extraction"
    },
    {
      "kind": "target_entity",
      "error_type": "missing",
      "expected": "重疾险",
      "actual": null,
      "evidence_ref": "adapter_extraction"
    }
  ],
  "wrong": [
    {
      "kind": "intent_label",
      "error_type": "wrong_value",
      "expected": "customer_portrait",
      "actual": "other",
