      "error_type": "wrong_value",
      "expected": "不是“其他意图”",
      "actual": "其他意图",
      "evidence_ref": "adapter_extraction"
    }
  ],
  "extra": [],
  "evidence": [
    {
      "source": "extracted_output",
      "intent": "other",
      "confidence": 0.5,
      "target_value": null,
      "subIntent": "其他意图"
